    for p in patterns:
        m = re.search(p, text, re.IGNORECASE)
        if m:
            name = m.group(1).strip()
            # cleanup trailing articles
            name = re.sub(r"\s+(the|a)$", "", name, flags=re.IGNORECASE)
            return name.upper()
    # fallback: take up to first comma
    part = text.split(',')[0]
    return part.strip().upper()

for r in citing_rows:
